import React, { useEffect, useRef, useState } from 'react';
import './VideoPlayer.css';

export default function VideoPlayer({
  videoUrl,
  title = 'Video',
  thumbnail = null,
  onPlaybackStart = null,
  onProgress = null,
  onEnded = null
}) {
  const videoRef = useRef(null);
  const containerRef = useRef(null);
  const [playing, setPlaying] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [volume, setVolume] = useState(1);
  const [fullscreen, setFullscreen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showControls, setShowControls] = useState(true);
  const controlsTimeoutRef = useRef(null);

  // Format time in MM:SS format
  const formatTime = (seconds) => {
    if (!seconds || isNaN(seconds)) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  // Handle video play
  const handlePlay = () => {
    setPlaying(true);
    if (onPlaybackStart) {
      onPlaybackStart();
    }
  };

  // Handle video pause
  const handlePause = () => {
    setPlaying(false);
  };

  // Handle video time update
  const handleTimeUpdate = () => {
    if (videoRef.current) {
      setCurrentTime(videoRef.current.currentTime);
      if (onProgress) {
        onProgress({
          currentTime: videoRef.current.currentTime,
          duration: videoRef.current.duration,
          played: videoRef.current.currentTime / videoRef.current.duration
        });
      }
    }
  };

  // Handle video loaded metadata
  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      setDuration(videoRef.current.duration);
    }
    setLoading(false);
  };

  // Handle video error
  const handleVideoError = () => {
    setError('Failed to load video. Please try again later.');
    setLoading(false);
  };

  // Handle video ended
  const handleVideoEnded = () => {
    setPlaying(false);
    if (onEnded) {
      onEnded();
    }
  };

  // Handle play/pause toggle
  const togglePlayPause = () => {
    if (videoRef.current) {
      if (playing) {
        videoRef.current.pause();
      } else {
        videoRef.current.play().catch(err => {
          console.error('Play error:', err);
        });
      }
    }
  };

  // Handle seek
  const handleSeek = (e) => {
    const container = containerRef.current;
    if (!container) return;

    const rect = container.querySelector('.progress-bar').getBoundingClientRect();
    const pos = (e.clientX - rect.left) / rect.width;
    const newTime = pos * duration;

    if (videoRef.current) {
      videoRef.current.currentTime = Math.max(0, Math.min(newTime, duration));
      setCurrentTime(videoRef.current.currentTime);
    }
  };

  // Handle volume change
  const handleVolumeChange = (e) => {
    const newVolume = parseFloat(e.target.value);
    setVolume(newVolume);
    if (videoRef.current) {
      videoRef.current.volume = newVolume;
    }
  };

  // Handle fullscreen toggle
  const toggleFullscreen = async () => {
    try {
      if (fullscreen) {
        if (document.fullscreenElement) {
          await document.exitFullscreen();
        }
        setFullscreen(false);
      } else {
        if (containerRef.current) {
          await containerRef.current.requestFullscreen();
          setFullscreen(true);
        }
      }
    } catch (err) {
      console.error('Fullscreen error:', err);
    }
  };

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyPress = (e) => {
      if (!videoRef.current) return;

      switch (e.code) {
        case 'Space':
          e.preventDefault();
          togglePlayPause();
          break;
        case 'ArrowLeft':
          videoRef.current.currentTime = Math.max(0, videoRef.current.currentTime - 5);
          break;
        case 'ArrowRight':
          videoRef.current.currentTime = Math.min(duration, videoRef.current.currentTime + 5);
          break;
        case 'KeyM':
          setVolume(volume === 0 ? 1 : 0);
          if (videoRef.current) {
            videoRef.current.volume = volume === 0 ? 1 : 0;
          }
          break;
        case 'KeyF':
          toggleFullscreen();
          break;
        default:
          break;
      }
    };

    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [playing, duration, volume]);

  // Handle controls visibility on mouse move
  const handleMouseMove = () => {
    setShowControls(true);
    if (controlsTimeoutRef.current) {
      clearTimeout(controlsTimeoutRef.current);
    }

    if (playing) {
      controlsTimeoutRef.current = setTimeout(() => {
        setShowControls(false);
      }, 3000);
    }
  };

  useEffect(() => {
    return () => {
      if (controlsTimeoutRef.current) {
        clearTimeout(controlsTimeoutRef.current);
      }
    };
  }, []);

  if (error) {
    return (
      <div className="video-player-error">
        <div className="error-icon">⚠️</div>
        <div className="error-title">Video Unavailable</div>
        <div className="error-message">{error}</div>
      </div>
    );
  }

  return (
    <div
      className="video-player-container"
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={() => playing && setShowControls(false)}
    >
      {loading && (
        <div className="video-loader">
          <div className="spinner" />
        </div>
      )}

      <video
        ref={videoRef}
        className="video-element"
        preload="metadata"
        poster={thumbnail}
        onPlay={handlePlay}
        onPause={handlePause}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={handleLoadedMetadata}
        onError={handleVideoError}
        onEnded={handleVideoEnded}
        onLoadStart={() => setLoading(true)}
      >
        <source src={videoUrl} type="video/mp4" />
        Your browser does not support the video tag.
      </video>

      {/* Controls */}
      <div className={`video-controls ${showControls ? 'visible' : 'hidden'}`}>
        {/* Progress bar */}
        <div className="progress-bar-container">
          <div
            className="progress-bar"
            onClick={handleSeek}
            style={{ cursor: 'pointer' }}
          >
            <div
              className="progress-fill"
              style={{
                width: `${(currentTime / duration) * 100 || 0}%`
              }}
            />
            <div
              className="progress-handle"
              style={{
                left: `${(currentTime / duration) * 100 || 0}%`
              }}
            />
          </div>
        </div>

        {/* Control buttons */}
        <div className="controls-bottom">
          {/* Left side: Play, Volume */}
          <div className="controls-left">
            <button
              className="control-btn play-btn"
              onClick={togglePlayPause}
              title={playing ? 'Pause (Space)' : 'Play (Space)'}
            >
              {playing ? '⏸' : '▶'}
            </button>

            <div className="volume-control">
              <button
                className="control-btn"
                onClick={() => {
                  const newVol = volume === 0 ? 1 : 0;
                  setVolume(newVol);
                  if (videoRef.current) {
                    videoRef.current.volume = newVol;
                  }
                }}
                title="Mute (M)"
              >
                {volume === 0 ? '🔇' : volume < 0.5 ? '🔉' : '🔊'}
              </button>
              <input
                type="range"
                min="0"
                max="1"
                step="0.1"
                value={volume}
                onChange={handleVolumeChange}
                className="volume-slider"
                title="Volume"
              />
            </div>

            <span className="time-display">
              {formatTime(currentTime)} / {formatTime(duration)}
            </span>
          </div>

          {/* Right side: Fullscreen */}
          <div className="controls-right">
            <button
              className="control-btn fullscreen-btn"
              onClick={toggleFullscreen}
              title={fullscreen ? 'Exit Fullscreen (F)' : 'Fullscreen (F)'}
            >
              {fullscreen ? '⛶' : '⛶'}
            </button>
          </div>
        </div>
      </div>

      {/* Title overlay */}
      <div className="video-title-overlay">
        <h2>{title}</h2>
      </div>
    </div>
  );
}
